void RoiClusterFusionNode::fuse_on_single_image(
  const ClusterMsgType & input_cluster_msg, const Det2dStatus<RoiMsgType> & det2d_status,
  const RoiMsgType & input_rois_msg, ClusterMsgType & output_cluster_msg)
{
  std::unique_ptr<ScopedTimeTrack> st_ptr;
  if (time_keeper_) st_ptr = std::make_unique<ScopedTimeTrack>(__func__, *time_keeper_);

  const sensor_msgs::msg::CameraInfo & camera_info =
    det2d_status.camera_projector_ptr->getCameraInfo();

  // get transform from cluster frame id to camera optical frame id
  geometry_msgs::msg::TransformStamped transform_stamped;
  {
    const auto transform_stamped_optional = getTransformStamped(
      tf_buffer_, /*target*/ input_rois_msg.header.frame_id,
      /*source*/ input_cluster_msg.header.frame_id, input_rois_msg.header.stamp);
    if (!transform_stamped_optional) {
      RCLCPP_WARN_STREAM(
        get_logger(), "Failed to get transform from " << input_cluster_msg.header.frame_id << " to "
                                                      << input_rois_msg.header.frame_id);
      return;
    }
    transform_stamped = transform_stamped_optional.value();
  }

  std::map<std::size_t, RegionOfInterest> m_cluster_roi;

  std::vector<sensor_msgs::msg::RegionOfInterest> debug_image_rois;
  std::vector<Eigen::Vector2d> debug_obstacle_points;
  std::vector<sensor_msgs::msg::RegionOfInterest> debug_obstacle_rois;
  std::vector<double> debug_max_iou_for_image_rois;

  for (std::size_t i = 0; i < input_cluster_msg.feature_objects.size(); ++i) {
    if (input_cluster_msg.feature_objects.at(i).feature.cluster.data.empty()) {
      continue;
    }

    if (is_far_enough(input_cluster_msg.feature_objects.at(i), fusion_distance_)) {
      continue;
    }

    // filter point out of scope
    if (debugger_ && out_of_scope(input_cluster_msg.feature_objects.at(i))) {
      continue;
    }

    sensor_msgs::msg::PointCloud2 transformed_cluster;
    tf2::doTransform(
      input_cluster_msg.feature_objects.at(i).feature.cluster, transformed_cluster,
      transform_stamped);

    int min_x(camera_info.width), min_y(camera_info.height), max_x(0), max_y(0);
    std::vector<Eigen::Vector2d> projected_points;
    projected_points.reserve(transformed_cluster.data.size());
    for (sensor_msgs::PointCloud2ConstIterator<float> iter_x(transformed_cluster, "x"),
         iter_y(transformed_cluster, "y"), iter_z(transformed_cluster, "z");
         iter_x != iter_x.end(); ++iter_x, ++iter_y, ++iter_z) {
      if (*iter_z <= 0.0) {
        continue;
      }

      Eigen::Vector2d projected_point;
      if (det2d_status.camera_projector_ptr->calcImageProjectedPoint(
            cv::Point3d(*iter_x, *iter_y, *iter_z), projected_point)) {
        const int px = static_cast<int>(projected_point.x());
        const int py = static_cast<int>(projected_point.y());

        min_x = std::min(px, min_x);
        min_y = std::min(py, min_y);
        max_x = std::max(px, max_x);
        max_y = std::max(py, max_y);

        projected_points.push_back(projected_point);
        if (debugger_) debug_obstacle_points.push_back(projected_point);
      }
    }
    if (projected_points.empty()) {
      continue;
    }

    sensor_msgs::msg::RegionOfInterest roi;
    roi.x_offset = min_x;
    roi.y_offset = min_y;
    roi.width = max_x - min_x;
    roi.height = max_y - min_y;
    m_cluster_roi.emplace(i, roi);
    if (debugger_) debug_obstacle_rois.push_back(roi);
  }

  for (const auto & feature_obj : input_rois_msg.feature_objects) {
    int index = -1;
    bool associated = false;
    double max_iou = 0.0;
    const auto obj_label = getHighestProbLabel(feature_obj.object.classification);
    const float obj_class_iou_threshold = iou_threshold_.get_class_iou_thresh(obj_label);
    auto image_roi = feature_obj.feature.roi;
    sanitizeROI(image_roi, camera_info.width, camera_info.height);
    const bool is_roi_label_known = obj_label != ObjectClassification::UNKNOWN;
    for (const auto & cluster_map : m_cluster_roi) {
      double iou(0.0);
      bool use_rough_iou_match = is_far_enough(
        input_cluster_msg.feature_objects.at(cluster_map.first), strict_iou_fusion_distance_);
      auto cluster_roi = cluster_map.second;
      sanitizeROI(cluster_roi, camera_info.width, camera_info.height);
      if (use_rough_iou_match || (!is_roi_label_known)) {
        iou = cal_iou_by_mode(cluster_roi, image_roi, rough_iou_match_mode_);
      } else {
        iou = cal_iou_by_mode(cluster_roi, image_roi, strict_iou_match_mode_);
      }

      const bool passed_inside_cluster_gate =
        only_allow_inside_cluster_ ? is_inside(image_roi, cluster_roi, roi_scale_factor_) : true;
      if (max_iou < iou && passed_inside_cluster_gate) {
        index = cluster_map.first;
        max_iou = iou;
        associated = true;
      }
    }

    if (!associated) {
      continue;
    }

    if (!output_cluster_msg.feature_objects.empty()) {
      auto & fused_object = output_cluster_msg.feature_objects.at(index).object;
      const bool is_roi_existence_prob_higher =
        fused_object.existence_probability <= feature_obj.object.existence_probability;
      const bool is_roi_iou_over_threshold = obj_class_iou_threshold < max_iou;

      if (is_roi_iou_over_threshold && is_roi_existence_prob_higher) {
        // Get the label from the image ROI
        const uint8_t roi_label = getHighestProbLabel(feature_obj.object.classification);

        // Get the cluster pointcloud for 3D size validation
        const auto & cluster_pointcloud =
          input_cluster_msg.feature_objects.at(index).feature.cluster;

        const bool passes_size_validation = validateSizeForClass(cluster_pointcloud, roi_label);

        if (passes_size_validation) {
          fused_object.classification = feature_obj.object.classification;
          // Update existence_probability for fused objects
          fused_object.existence_probability =
            std::clamp(feature_obj.object.existence_probability, min_roi_existence_prob_, 1.0f);
        } else {
          RCLCPP_DEBUG(
            get_logger(), "Size validation failed for label %d, skipping fusion", roi_label);
        }
      }
    }
    if (debugger_) debug_image_rois.push_back(feature_obj.feature.roi);
    if (debugger_) debug_max_iou_for_image_rois.push_back(max_iou);
  }

  // note: debug objects are safely cleared in fusion_node.cpp
  // TODO(badai-nguyen): revise the shared debugger_ usage
  if (debugger_) {
    debugger_->image_rois_ = debug_image_rois;
    debugger_->obstacle_rois_ = debug_obstacle_rois;
    debugger_->obstacle_points_ = debug_obstacle_points;
    debugger_->max_iou_for_image_rois_ = debug_max_iou_for_image_rois;
    debugger_->publishImage(det2d_status.id, input_rois_msg.header.stamp);
  }
}

std::optional<geometry_msgs::msg::TransformStamped> getTransformStamped(
  const tf2_ros::Buffer & tf_buffer, const std::string & target_frame_id,
  const std::string & source_frame_id, const rclcpp::Time & time)
{
  try {
    geometry_msgs::msg::TransformStamped transform_stamped;
    transform_stamped = tf_buffer.lookupTransform(
      target_frame_id, source_frame_id, time, rclcpp::Duration::from_seconds(0.01));
    return transform_stamped;
  } catch (tf2::TransformException & ex) {
    RCLCPP_WARN_STREAM(rclcpp::get_logger("image_projection_based_fusion"), ex.what());
    return std::nullopt;
  }
}

double RoiClusterFusionNode::cal_iou_by_mode(
  const sensor_msgs::msg::RegionOfInterest & roi_1,
  const sensor_msgs::msg::RegionOfInterest & roi_2, const std::string iou_mode)
{
  switch (IOU_MODE_MAP.at(iou_mode)) {
    case 0 /* use iou mode */:
      return calcIoU(roi_1, roi_2);

    case 1 /* use iou_x mode */:
      return calcIoUX(roi_1, roi_2);

    case 2 /* use iou_y mode */:
      return calcIoUY(roi_1, roi_2);
    default:
      return 0.0;
  }
}

double calcIoU(
  const sensor_msgs::msg::RegionOfInterest & roi_1,
  const sensor_msgs::msg::RegionOfInterest & roi_2)
{
  double s_1, s_2;
  s_1 = static_cast<double>(roi_1.width * static_cast<double>(roi_1.height));
  s_2 = static_cast<double>(roi_2.width * static_cast<double>(roi_2.height));

  double overlap_s;
  double overlap_max_x, overlap_max_y, overlap_min_x, overlap_min_y;
  overlap_min_x = roi_1.x_offset < roi_2.x_offset ? roi_2.x_offset : roi_1.x_offset;
  overlap_min_y = roi_1.y_offset < roi_2.y_offset ? roi_2.y_offset : roi_1.y_offset;
  overlap_max_x = roi_1.x_offset + roi_1.width < roi_2.x_offset + roi_2.width
                    ? roi_1.x_offset + roi_1.width
                    : roi_2.x_offset + roi_2.width;
  overlap_max_y = roi_1.y_offset + roi_1.height < roi_2.y_offset + roi_2.height
                    ? roi_1.y_offset + roi_1.height
                    : roi_2.y_offset + roi_2.height;
  overlap_s = (overlap_max_x - overlap_min_x) * (overlap_max_y - overlap_min_y);
  if (overlap_max_x < overlap_min_x || overlap_max_y < overlap_min_y) {
    return 0.0;
  }
  return overlap_s / (s_1 + s_2 - overlap_s);
}

double calcIoUX(
  const sensor_msgs::msg::RegionOfInterest & roi_1,
  const sensor_msgs::msg::RegionOfInterest & roi_2)
{
  double s_1, s_2;
  s_1 = static_cast<double>(roi_1.width);
  s_2 = static_cast<double>(roi_2.width);
  double overlap_s;
  double overlap_max_x, overlap_max_y, overlap_min_x, overlap_min_y;
  overlap_min_x = roi_1.x_offset < roi_2.x_offset ? roi_2.x_offset : roi_1.x_offset;
  overlap_min_y = roi_1.y_offset < roi_2.y_offset ? roi_2.y_offset : roi_1.y_offset;
  overlap_max_x = roi_1.x_offset + roi_1.width < roi_2.x_offset + roi_2.width
                    ? roi_1.x_offset + roi_1.width
                    : roi_2.x_offset + roi_2.width;
  overlap_max_y = roi_1.y_offset + roi_1.height < roi_2.y_offset + roi_2.height
                    ? roi_1.y_offset + roi_1.height
                    : roi_2.y_offset + roi_2.height;
  overlap_s = (overlap_max_x - overlap_min_x);
  if (overlap_max_x < overlap_min_x || overlap_max_y < overlap_min_y) {
    return 0.0;
  }
  return overlap_s / (s_1 + s_2 - overlap_s);
}

double calcIoUY(
  const sensor_msgs::msg::RegionOfInterest & roi_1,
  const sensor_msgs::msg::RegionOfInterest & roi_2)
{
  double s_1, s_2;
  s_1 = static_cast<double>(roi_1.height);
  s_2 = static_cast<double>(roi_2.height);
  double overlap_s;
  double overlap_max_x, overlap_max_y, overlap_min_x, overlap_min_y;
  overlap_min_x = roi_1.x_offset < roi_2.x_offset ? roi_2.x_offset : roi_1.x_offset;
  overlap_min_y = roi_1.y_offset < roi_2.y_offset ? roi_2.y_offset : roi_1.y_offset;
  overlap_max_x = roi_1.x_offset + roi_1.width < roi_2.x_offset + roi_2.width
                    ? roi_1.x_offset + roi_1.width
                    : roi_2.x_offset + roi_2.width;
  overlap_max_y = roi_1.y_offset + roi_1.height < roi_2.y_offset + roi_2.height
                    ? roi_1.y_offset + roi_1.height
                    : roi_2.y_offset + roi_2.height;
  overlap_s = (overlap_max_y - overlap_min_y);
  if (overlap_max_x < overlap_min_x || overlap_max_y < overlap_min_y) {
    return 0.0;
  }
  return overlap_s / (s_1 + s_2 - overlap_s);
}

bool RoiClusterFusionNode::validateSizeForClass(
  const sensor_msgs::msg::PointCloud2 & cluster, const uint8_t label)
{
  // NOTE: Currently only validate pedestrians, the other classes are passed through
  switch (label) {
    case ObjectClassification::PEDESTRIAN:
      return validatePedestrianSize(cluster, pedestrian_size_params_);
    default:
      return true;
  }
}

inline bool validatePedestrianSize(
  const sensor_msgs::msg::PointCloud2 & cluster, const PedestrianSizeValidationParams & params)
{
  if (!params.enable_size_validation) {
    return true;  // Validation disabled
  }

  // Check 3D size from pointcloud cluster
  if (!cluster.data.empty()) {
    if (!isPedestrian3DSizeValidated(cluster, params)) {
      return false;
    }
  }

  return true;
}

inline bool isPedestrian3DSizeValidated(
  const sensor_msgs::msg::PointCloud2 & cluster, const PedestrianSizeValidationParams & params)
{
  // Calculate dimensions from pointcloud cluster (x-y footprint only)
  const auto dimensions = calculateClusterDimensions(cluster);
  if (!dimensions.has_value()) {
    return false;
  }

  // Check length
  if (dimensions->first < params.min_width) {
    return false;
  }
  if (dimensions->first > params.max_width) {
    return false;
  }
  // Check width
  if (dimensions->second < params.min_width) {
    return false;
  }
  if (dimensions->second > params.max_width) {
    return false;
  }
  return true;
}

inline std::optional<std::pair<double, double>> calculateClusterDimensions(
  const sensor_msgs::msg::PointCloud2 & cluster)
{
  if (cluster.data.empty()) {
    return std::nullopt;
  }

  // Initialize min/max values (x-y only)
  double min_x = std::numeric_limits<double>::max();
  double max_x = std::numeric_limits<double>::lowest();
  double min_y = std::numeric_limits<double>::max();
  double max_y = std::numeric_limits<double>::lowest();

  // Iterate through all points in the cluster
  size_t valid_points = 0;
  for (sensor_msgs::PointCloud2ConstIterator<float> iter_x(cluster, "x"), iter_y(cluster, "y"),
       iter_z(cluster, "z");
       iter_x != iter_x.end(); ++iter_x, ++iter_y, ++iter_z) {
    // Skip invalid points
    if (!std::isfinite(*iter_x) || !std::isfinite(*iter_y) || !std::isfinite(*iter_z)) {
      continue;
    }

    min_x = std::min(min_x, static_cast<double>(*iter_x));
    max_x = std::max(max_x, static_cast<double>(*iter_x));
    min_y = std::min(min_y, static_cast<double>(*iter_y));
    max_y = std::max(max_y, static_cast<double>(*iter_y));
    valid_points++;
  }

  if (valid_points == 0) {
    return std::nullopt;
  }

  // Calculate dimensions (x-y footprint only)
  double length = max_x - min_x;
  double width = max_y - min_y;

  // Ensure non-zero dimensions
  if (length <= 0.0 || width <= 0.0) {
    return std::nullopt;
  }

  return std::make_pair(length, width);
}
